    "inputs": {
      "message": {
        "kind": "object",
        "type": "object",
        "value_type": "text",
        "required": true,
        "from": "edge.message",
        "accepts": [
          "scalar:text",
          "object",
          "file:text",
          "file:markdown",
          "file:json"
        ],
        "resolvers": [
          {
            "id": "direct-text",
            "kind": "direct"
          },
          {
            "id": "metadata-title",
            "kind": "json_path",
            "path": "$.title"
          },
          {
            "id": "metadata-description",
            "kind": "json_path",
            "path": "$.description"
          }
        ]
      },
      "index": {
        "kind": "file",
        "type": "file",
        "value_type": "markdown",
        "required": false,
        "from": "wiki-build.outputs.index",
        "accepts": [
          "file:markdown",
          "file:text"
        ]
      }
    },
    "outputs": {
      "telegram_message": {
        "kind": "file",
        "type": "file",
        "value_type": "json",
        "relayable": false,
        "path": "logs/pipeline-runs/pipe-{run_id}.json"
      }
    },
    "capabilities": [
      "git",
      "sse",
      "telegram"
    ]
  }
}

